const row = $input.first().json;

if (!row || !row.user_id) {
  return [{
    json: {
      error: "USER_NOT_FOUND"
    }
  }];
}

return [{
  json: {
    data: {
      user: {
        id: row.user_id,
        telegram_user_id: row.telegram_user_id,
        username: row.username,
        first_name: row.first_name,
        last_name: row.last_name,
        language_code:
          row.settings_language_code ||
          row.user_language_code
      },
      settings: row.base_currency
        ? {
            base_currency: row.base_currency,
            report_currency: row.report_currency,
            language_code: row.settings_language_code,
            current_workspace_id: row.current_workspace_id,
            default_expense_account_id: row.default_expense_account_id,
            default_income_account_id: row.default_income_account_id
          }
        : null,
      workspace: row.workspace_id
        ? {
            id: row.workspace_id,
            name: row.workspace_name,
            workspace_type: row.workspace_type
          }
        : null
    }
  }
}];

const row = $input.first().json;

if (!row || !row.user_id) {
  return [{ json: { error: "USER_NOT_FOUND" } }];
}

return [{
  json: {
    data: {
      period: {
        date_from: row.date_from,
        date_to: row.date_to
      },
      summary: {
        net_worth: Number(row.net_worth || 0),
        income_month: Number(row.income_month || 0),
        expenses_month: Number(row.expenses_month || 0),
        result_month: Number(row.result_month || 0),
        currency: row.report_currency
      },
      balances_by_currency: row.balances_by_currency || [],
      latest_operations: row.latest_operations || []
    }
  }
}];

const row = $input.first().json;

if (!row || !row.user_id) {
  return [{
    json: {
      error: "USER_NOT_FOUND"
    }
  }];
}

const flatAccounts = row.accounts || [];

const byId = new Map();

for (const account of flatAccounts) {
  byId.set(account.id, {
    ...account,
    balance_original: Number(account.balance_original || 0),
    balance_base: Number(account.balance_base || 0),
    children: []
  });
}

const roots = [];

for (const account of byId.values()) {
  if (account.parent_id && byId.has(account.parent_id)) {
    byId.get(account.parent_id).children.push(account);
  } else {
    roots.push(account);
  }
}

function sortTree(items) {
  items.sort((a, b) => {
    const sa = Number(a.sort_order || 0);
    const sb = Number(b.sort_order || 0);

    if (sa !== sb) return sa - sb;

    return String(a.name || "").localeCompare(String(b.name || ""));
  });

  for (const item of items) {
    sortTree(item.children);
  }
}

sortTree(roots);

return [{
  json: {
    data: {
      base_currency: row.base_currency,
      total_base: Number(row.total_base || 0),
      accounts: roots
    }
  }
}];

const row = $input.first().json;

if (!row || !row.user_id) {
  return [{
    json: {
      error: "USER_NOT_FOUND"
    }
  }];
}

return [{
  json: {
    data: {
      language_code: row.language_code,
      messages: row.messages || {}
    }
  }
}];

const headers = $json.headers || {};
const query = $json.query || {};

const initData =
  headers["x-telegram-init-data"] ||
  headers["X-Telegram-Init-Data"] ||
  query.initData ||
  query.init_data ||
  null;

const path =
  query.endpoint ||
  $json.path ||
  "/api/v1/me";

return [{
  json: {
    method: $json.httpMethod || "GET",
    path,
    initData
  }
}];

const crypto = require("crypto");

const initData = $json.initData;

if (!initData) {
  throw new Error("INIT_DATA_MISSING");
}

const botToken = $env.MONEYTRACK_BOT_TOKEN;

if (!botToken) {
  throw new Error("BOT_TOKEN_MISSING");
}

function parseInitData(initData) {
  const result = {};

  for (const part of initData.split("&")) {
    const eqIndex = part.indexOf("=");

    if (eqIndex === -1) continue;

    const key = decodeURIComponent(part.slice(0, eqIndex));
    const value = decodeURIComponent(part.slice(eqIndex + 1));

    result[key] = value;
  }

  return result;
}

const params = parseInitData(initData);
const receivedHash = params.hash;

if (!receivedHash) {
  throw new Error("HASH_MISSING");
}

delete params.hash;

const dataCheckString = Object.keys(params)
  .sort()
  .map((key) => `${key}=${params[key]}`)
  .join("\n");

const secretKey = crypto
  .createHmac("sha256", "WebAppData")
  .update(botToken)
  .digest();

const calculatedHash = crypto
  .createHmac("sha256", secretKey)
  .update(dataCheckString)
  .digest("hex");

if (calculatedHash !== receivedHash) {
  throw new Error("INVALID_INIT_DATA_HASH");
}

const user = JSON.parse(params.user);

return [{
  json: {
    path: $json.path,
    method: $json.method,

    telegram_user_id: user.id,
    username: user.username || null,
    first_name: user.first_name || null,
    last_name: user.last_name || null,
    language_code: user.language_code || null
  }
}];

